# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System.Collections.Generic;

public class PlayerStatsManager : MonoBehaviour
{
    // Player Stats
    [Header("Player Stats")]
    public int currentHealth = 100;
    public int maxHealth = 100;
    public int currentCurrency = 500;
    public int baseAttackPower = 10;
    public int defense = 0; // Example stat for damage reduction

    // --- Damage System ---
    public void TakeDamage(int baseDamage)
    {
        // Simple client-side damage calculation
        // Damage = Base Damage - Defense (with a minimum of 1 damage)
        int calculatedDamage = Mathf.Max(1, baseDamage - defense);

        currentHealth -= calculatedDamage;
        currentHealth = Mathf.Max(0, currentHealth); // Ensure health doesn't go below 0

        Debug.Log($"Player took {calculatedDamage} damage. Current Health: {currentHealth}");

        if (currentHealth <= 0)
        {
            Debug.Log("Player has been defeated!");
            // Implement game over logic here
        }
    }

    // --- Shop System ---

    [System.Serializable]
    public class ShopItem
    {
        public string itemName;
        public string description;
        public int price;
        public int healthBoost; // How much health this item adds
        public int currencyBoost; // How much currency this item adds (e.g., a currency pack)
        public int attackPowerBoost; // How much attack power this item adds
        public int defenseBoost; // How much defense this item adds
        public bool isConsumable = false; // Can be bought multiple times, or is a permanent upgrade
    }

    [Header("Shop Items")]
    public List<ShopItem> availableShopItems = new List<ShopItem>();

    private void Start()
    {
        // Example shop items (can be set up in the Inspector)
        if (availableShopItems.Count == 0)
        {
            availableShopItems.Add(new ShopItem { itemName = "Health Potion", description = "Restores 30 health.", price = 50, healthBoost = 30, isConsumable = true });
            availableShopItems.Add(new ShopItem { itemName = "Iron Sword", description = "Increases attack by 5.", price = 200, attackPowerBoost = 5, isConsumable = false });
            availableShopItems.Add(new ShopItem { itemName = "Shield Upgrade", description = "Increases defense by 2.", price = 150, defenseBoost = 2, isConsumable = false });
            availableShopItems.Add(new ShopItem { itemName = "Coin Pack (Small)", description = "Adds 100 coins.", price = 0, currencyBoost = 100, isConsumable = true }); // Example of an IAP-like item for currency
        }
    }

    public bool TryPurchaseItem(ShopItem item)
    {
        if (item == null)
        {
            Debug.LogError("Attempted to purchase a null item.");
            return false;
        }

        if (currentCurrency >= item.price)
        {
            // Deduct cost
            currentCurrency -= item.price;

            // Apply item effects
            currentHealth = Mathf.Min(maxHealth, currentHealth + item.healthBoost);
            currentCurrency += item.currencyBoost; // For items that give currency (e.g., IAP packs)
            baseAttackPower += item.attackPowerBoost;
            defense += item.defenseBoost;

            Debug.Log($"Purchased '{item.itemName}' for {item.price} currency. Current Currency: {currentCurrency}");
            Debug.Log($"Player Stats after purchase: Health={currentHealth}, Attack={baseAttackPower}, Defense={defense}");
            return true;
        }
        else
        {
            Debug.Log($"Not enough currency to buy '{item.itemName}'. Needed: {item.price}, Had: {currentCurrency}");
            return false;
        }
    }

    // --- Example Usage ---
    // You can call these methods from other scripts, UI buttons, or game events.
    void Update()
    {
        // Example: Press 'D' to take damage
        if (Input.GetKeyDown(KeyCode.D))
        {
            TakeDamage(20); // Take 20 base damage
        }

        // Example: Press 'P' to try and purchase the first item in the list
        if (Input.GetKeyDown(KeyCode.P))
        {
            if (availableShopItems.Count > 0)
            {
                TryPurchaseItem(availableShopItems[0]);
            }
            else
            {
                Debug.Log("No items available in the shop to purchase.");
            }
        }
        
        // Example: Press 'C' to add currency (simulating IAP or a pickup)
        if (Input.GetKeyDown(KeyCode.C))
        {
            AddCurrency(100);
            Debug.Log($"Added 100 currency. Current Currency: {currentCurrency}");
        }
    }

    public void AddCurrency(int amount)
    {
        currentCurrency += amount;
    }
}